 * se empareja inmediatamente con la que lleva m�s tiempo esperando
 * (la de ticket m�s antiguo). En caso contrario, espera en la
 * variable de condici�n hasta que alguien del sexo opuesto llegue
 * y forme pareja.
 */

/* �Cu�ntos tickets podemos almacenar como m�ximo.
 * Debe ser mayor que el total de llamadas a dama() o varon().
 * Con las pruebas incluidas, el m�ximo es 10000 por sexo. */
#define MAX_TICKETS 131072

/* ------------------------------------------------------------------ */
/* Variables globales                                                  */
/* ------------------------------------------------------------------ */

static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
static pthread_cond_t  cond  = PTHREAD_COND_INITIALIZER;

/* Distribuidores de tickets para damas y varones.
 * - dama_next / varon_next:     pr�ximo ticket a asignar
 * - dama_serving / varon_serving: ticket de la pr�xima persona en
 *   espera que ser� emparejada (s�lo cuenta a quienes efectivamente
 *   esperaron). */
static int dama_next    = 0;
static int dama_serving = 0;
static int varon_next    = 0;
static int varon_serving = 0;

/* Cantidad de personas actualmente en espera. */
static int n_damas_waiting  = 0;
static int n_varones_waiting = 0;

/* Almacenamiento indexado por ticket:
 * - name:  nombre de la persona
 * - partner: nombre de la pareja asignada
 * - matched: 1 si ya fue emparejada, 0 si a�n espera */
static char *dama_name[MAX_TICKETS];
static char *varon_name[MAX_TICKETS];
static char *dama_partner[MAX_TICKETS];
static char *varon_partner[MAX_TICKETS];
static int   dama_matched[MAX_TICKETS];
static int   varon_matched[MAX_TICKETS];

/* ------------------------------------------------------------------ */
/* discoInit / discoDestroy                                            */
/* ------------------------------------------------------------------ */

void discoInit(void) {
    /* Todas las variables globales se inicializan est�ticamente. */
}

void discoDestroy(void) {
    /* No hay memoria din�mica que liberar. */
}

/* ------------------------------------------------------------------ */
/* dama                                                                */
/* ------------------------------------------------------------------ */

char *dama(char *nom) {
    pthread_mutex_lock(&mutex);

    int my_ticket = dama_next++;
    dama_name[my_ticket]   = nom;
    dama_matched[my_ticket] = 0;

    /* �Hay varones esperando? Si es as�, emparejar con el m�s antiguo. */
    if (n_varones_waiting > 0) {
        int his_ticket = varon_serving++;
        n_varones_waiting--;

        varon_partner[his_ticket] = nom;
        varon_matched[his_ticket] = 1;

        char *partner = varon_name[his_ticket];
        pthread_cond_broadcast(&cond);
        pthread_mutex_unlock(&mutex);
        return partner;
    }

    /* No hay varones esperando: esperar hasta que uno llegue. */
    n_damas_waiting++;
    while (!dama_matched[my_ticket]) {
        pthread_cond_wait(&cond, &mutex);
    }
    /* Al llegar aqu�, n_damas_waiting ya fue decrementado por el
     * varon que nos emparej�. */

    char *partner = dama_partner[my_ticket];
    pthread_mutex_unlock(&mutex);
    return partner;
}

/* ------------------------------------------------------------------ */
/* varon                                                               */
/* ------------------------------------------------------------------ */

char *varon(char *nom) {
    pthread_mutex_lock(&mutex);

    int my_ticket = varon_next++;
    varon_name[my_ticket]   = nom;
    varon_matched[my_ticket] = 0;

    /* �Hay damas esperando? Si es as�, emparejar con la m�s antigua. */
    if (n_damas_waiting > 0) {
        int her_ticket = dama_serving++;
        n_damas_waiting--;

        dama_partner[her_ticket] = nom;
        dama_matched[her_ticket] = 1;

        char *partner = dama_name[her_ticket];
        pthread_cond_broadcast(&cond);
        pthread_mutex_unlock(&mutex);
        return partner;
    }

    /* No hay damas esperando: esperar hasta que una llegue. */
    n_varones_waiting++;
    while (!varon_matched[my_ticket]) {
        pthread_cond_wait(&cond, &mutex);
    }
    /* Al llegar aqu�, n_varones_waiting ya fue decrementado por la
     * dama que nos emparej�. */

    char *partner = varon_partner[my_ticket];
    pthread_mutex_unlock(&mutex);
    return partner;
}

